,p_chart_id=>wwv_flow_api.id(6782319290983546)
,p_seq=>10
,p_name=>'Series 1'
,p_data_source_type=>'SQL'
,p_data_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'    pr.product_name AS product,',
'    SUM(ol.quantity * pr.price) AS total_sales',
'FROM ',
'    ORDERPLACE op',
'JOIN ',
'    ORDERLIST ol ON op.orderplace_id = ol.orderplace_id',
'JOIN ',
'    PRODUCT pr ON ol.product_id = pr.product_id',
'JOIN ',
'    SHOP s ON pr.shop_id = s.shop_id',
'GROUP BY ',
'    pr.product_name;'))
,p_max_row_count=>20
,p_items_value_column_name=>'TOTAL_SALES'
,p_items_label_column_name=>'PRODUCT'
,p_line_type=>'auto'
,p_marker_rendered=>'auto'
,p_marker_shape=>'auto'
,p_assigned_to_y2=>'off'
,p_items_label_rendered=>false
);
